@_cdecl("_nitro_camera_register_frameStream_stream")
public func _nitro_camera_register_frameStream_stream(
    _ dartPort: Int64,
    _ emitCb: @convention(c) (Int64, UnsafeMutableRawPointer?) -> Bool
) {
    NitroCameraRegistry._frameStreamCancellables[dartPort] =
        NitroCameraRegistry.impl?.frameStream.sink { item in
            let ptr = UnsafeMutablePointer<_CameraFrameC>.allocate(capacity: 1)
            ptr.initialize(to: _CameraFrameC.fromSwift(item))
            if !emitCb(dartPort, UnsafeMutableRawPointer(ptr)) {
                ptr.deinitialize(count: 1)
                ptr.deallocate()
                NitroCameraRegistry._frameStreamCancellables.removeValue(forKey: dartPort)?.cancel()
            }
        }
}

@_cdecl("_nitro_camera_release_frameStream_stream")
public func _nitro_camera_release_frameStream_stream(_ dartPort: Int64) {
    NitroCameraRegistry._frameStreamCancellables[dartPort]?.cancel()
    NitroCameraRegistry._frameStreamCancellables.removeValue(forKey: dartPort)
}
@_cdecl("_nitro_camera_register_eventStream_stream")
public func _nitro_camera_register_eventStream_stream(
    _ dartPort: Int64,
    _ emitCb: @convention(c) (Int64, UnsafeMutablePointer<UInt8>?) -> Bool
) {
    NitroCameraRegistry._eventStreamCancellables[dartPort] =
        NitroCameraRegistry.impl?.eventStream
            .buffer(size: 64, prefetch: .byRequest, whenFull: .dropOldest)
            .sink { item in
                let raw = item.toNative()
